import{_ as s,o as a,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Troubleshooting | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/operations/troubleshooting.md","filePath":"guides/operations/troubleshooting.md","lastUpdated":1772446570000}');const l=s({name:"guides/operations/troubleshooting.md"},[["render",function(s,o,l,t,p,c){return a(),e("div",null,[...o[0]||(o[0]=[n('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Common issues and solutions when running Evolve nodes.</p><h2 id="diagnostic-commands" tabindex="-1">Diagnostic Commands <a class="header-anchor" href="#diagnostic-commands" aria-label="Permalink to &quot;Diagnostic Commands&quot;">​</a></h2><h3 id="check-node-status" tabindex="-1">Check Node Status <a class="header-anchor" href="#check-node-status" aria-label="Permalink to &quot;Check Node Status&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Health check</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:7331/health/live</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:7331/health/ready</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Node status</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:26657/status</span></span></code></pre></div><h3 id="view-logs" tabindex="-1">View Logs <a class="header-anchor" href="#view-logs" aria-label="Permalink to &quot;View Logs&quot;">​</a></h3><p>If running in the foreground, logs are printed to stderr by default. If running as a background service, use the appropriate command:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># foreground (default in dev)</span></span>\n<span class="line"><span style="color:#94EEFF;">./evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#BFF3C2;"> ...</span><span style="color:#888888;"> 2&gt;&amp;1</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> tee</span><span style="color:#BFF3C2;"> evnode.log</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># systemd service</span></span>\n<span class="line"><span style="color:#94EEFF;">journalctl</span><span style="color:#FFECB6;"> -u</span><span style="color:#BFF3C2;"> evnode</span><span style="color:#FFECB6;"> -f</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># docker container</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> logs</span><span style="color:#FFECB6;"> -f</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">container_nam</span><span style="color:#DBD7CA;">e</span><span style="color:#888888;">&gt;</span></span></code></pre></div><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="node-won-t-start" tabindex="-1">Node Won&#39;t Start <a class="header-anchor" href="#node-won-t-start" aria-label="Permalink to &quot;Node Won&#39;t Start&quot;">​</a></h3><p><strong>Symptom:</strong> Node exits immediately after starting.</p><p><strong>Solutions:</strong></p><ol><li>Check for port conflicts:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">lsof</span><span style="color:#FFECB6;"> -i</span><span style="color:#BFF3C2;"> :26657</span></span>\n<span class="line"><span style="color:#94EEFF;">lsof</span><span style="color:#FFECB6;"> -i</span><span style="color:#BFF3C2;"> :7676</span></span></code></pre></div><ol><li>Verify configuration file syntax:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cat</span><span style="color:#BFF3C2;"> ~/.evnode/config/evnode.yml</span></span></code></pre></div><ol><li>Check data directory permissions:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ls</span><span style="color:#FFECB6;"> -la</span><span style="color:#BFF3C2;"> ~/.evnode/data</span></span></code></pre></div><h3 id="da-connection-failures" tabindex="-1">DA Connection Failures <a class="header-anchor" href="#da-connection-failures" aria-label="Permalink to &quot;DA Connection Failures&quot;">​</a></h3><p><strong>Symptom:</strong> Logs show <code>DA layer submission failed</code> errors.</p><p><strong>Error example:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>ERR DA layer submission failed error=&quot;connection refused&quot;</span></span></code></pre></div><p><strong>Solutions:</strong></p><ol><li>Verify DA endpoint is reachable:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:26658/health</span></span></code></pre></div><ol><li>Check authentication token (Celestia):</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#BFF3C2;"> mocha</span></span></code></pre></div><ol><li>Verify DA node is fully synced:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> header</span><span style="color:#BFF3C2;"> sync-state</span></span></code></pre></div><h3 id="out-of-da-funds" tabindex="-1">Out of DA Funds <a class="header-anchor" href="#out-of-da-funds" aria-label="Permalink to &quot;Out of DA Funds&quot;">​</a></h3><p><strong>Symptom:</strong> <code>Code: 19</code> errors in logs.</p><p><strong>Error example:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>ERR DA layer submission failed error=&quot;Codespace: &#39;sdk&#39;, Code: 19, Message: &quot;</span></span></code></pre></div><p><strong>Solutions:</strong></p><ol><li>Check DA account balance</li><li>Fund the account with more tokens</li><li>Increase gas price to unstick pending transactions:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.da.gas_price</span><span style="color:#FFECB6;"> 0.05</span></span></code></pre></div><p>See <a href="/guides/restart-chain">Restart Chain Guide</a> for detailed steps.</p><h3 id="p2p-connection-issues" tabindex="-1">P2P Connection Issues <a class="header-anchor" href="#p2p-connection-issues" aria-label="Permalink to &quot;P2P Connection Issues&quot;">​</a></h3><p><strong>Symptom:</strong> Node not syncing, no peers connected.</p><p><strong>Solutions:</strong></p><ol><li>Verify peer address format:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Correct format</span></span>\n<span class="line"><span style="color:#94EEFF;">/ip4/1.2.3.4/tcp/7676/p2p/12D3KooWABC...</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># NOT just the peer ID</span></span>\n<span class="line"><span style="color:#94EEFF;">12D3KooWABC...</span></span></code></pre></div><ol><li>Check firewall allows P2P port:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">sudo</span><span style="color:#BFF3C2;"> ufw</span><span style="color:#BFF3C2;"> status</span></span>\n<span class="line"><span style="color:#A0A0A0;"># Ensure port 7676 (or your P2P port) is allowed</span></span></code></pre></div><ol><li>Try DA-only sync mode (no P2P):</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:26658</span></span>\n<span class="line"><span style="color:#A0A0A0;"># Leave --evnode.p2p.peers empty</span></span></code></pre></div><h3 id="node-falling-behind" tabindex="-1">Node Falling Behind <a class="header-anchor" href="#node-falling-behind" aria-label="Permalink to &quot;Node Falling Behind&quot;">​</a></h3><p><strong>Symptom:</strong> <code>catching_up: true</code> in status, height increasing slowly.</p><p><strong>Solutions:</strong></p><ol><li>Check system resources:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">htop</span></span>\n<span class="line"><span style="color:#94EEFF;">df</span><span style="color:#FFECB6;"> -h</span></span></code></pre></div><ol><li>Increase DA request timeout:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.da.request_timeout</span><span style="color:#BFF3C2;"> 60s</span></span></code></pre></div><ol><li>Verify DA layer is responding quickly:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">time</span><span style="color:#DBD7CA;"> curl http://localhost:26658/header/sync_state</span></span></code></pre></div><h3 id="execution-layer-desync" tabindex="-1">Execution Layer Desync <a class="header-anchor" href="#execution-layer-desync" aria-label="Permalink to &quot;Execution Layer Desync&quot;">​</a></h3><p><strong>Symptom:</strong> State root mismatches, execution errors.</p><p><strong>EVM (ev-reth):</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Check ev-reth logs for errors</span></span>\n<span class="line"><span style="color:#94EEFF;">journalctl</span><span style="color:#FFECB6;"> -u</span><span style="color:#BFF3C2;"> ev-reth</span><span style="color:#FFECB6;"> -f</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Verify Engine API connectivity</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#FFECB6;"> -X</span><span style="color:#BFF3C2;"> POST</span><span style="color:#FFECB6;"> -H</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Content-Type: application/json</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  -H</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Authorization: Bearer </span><span style="color:#767676;">$(</span><span style="color:#94EEFF;">cat</span><span style="color:#BFF3C2;"> jwt.hex</span><span style="color:#767676;">)</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --data</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">{&quot;jsonrpc&quot;:&quot;2.0&quot;,&quot;method&quot;:&quot;eth_blockNumber&quot;,&quot;params&quot;:[],&quot;id&quot;:1}</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#BFF3C2;">  http://localhost:8551</span></span></code></pre></div><p><strong>Cosmos SDK (ev-abci):</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Check app hash consistency</span></span>\n<span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:26657/status</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> jq</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.sync_info</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h2 id="reset-procedures" tabindex="-1">Reset Procedures <a class="header-anchor" href="#reset-procedures" aria-label="Permalink to &quot;Reset Procedures&quot;">​</a></h2><h3 id="soft-reset-keep-genesis" tabindex="-1">Soft Reset (Keep Genesis) <a class="header-anchor" href="#soft-reset-keep-genesis" aria-label="Permalink to &quot;Soft Reset (Keep Genesis)&quot;">​</a></h3><p>Reset state while keeping configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Stop the node</span></span>\n<span class="line"><span style="color:#94EEFF;">systemctl</span><span style="color:#BFF3C2;"> stop</span><span style="color:#BFF3C2;"> evnode</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Clear data directory</span></span>\n<span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#FFECB6;"> -rf</span><span style="color:#BFF3C2;"> ~/.evnode/data/</span><span style="color:#FFECB6;">*</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Restart</span></span>\n<span class="line"><span style="color:#94EEFF;">systemctl</span><span style="color:#BFF3C2;"> start</span><span style="color:#BFF3C2;"> evnode</span></span></code></pre></div><h3 id="hard-reset-full-reinitialize" tabindex="-1">Hard Reset (Full Reinitialize) <a class="header-anchor" href="#hard-reset-full-reinitialize" aria-label="Permalink to &quot;Hard Reset (Full Reinitialize)&quot;">​</a></h3><p>Complete reset including configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Stop the node</span></span>\n<span class="line"><span style="color:#94EEFF;">systemctl</span><span style="color:#BFF3C2;"> stop</span><span style="color:#BFF3C2;"> evnode</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Remove everything</span></span>\n<span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#FFECB6;"> -rf</span><span style="color:#BFF3C2;"> ~/.evnode</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Reinitialize</span></span>\n<span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> init</span></span></code></pre></div><h3 id="reset-evm-state-ev-reth" tabindex="-1">Reset EVM State (ev-reth) <a class="header-anchor" href="#reset-evm-state-ev-reth" aria-label="Permalink to &quot;Reset EVM State (ev-reth)&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Stop both nodes</span></span>\n<span class="line"><span style="color:#94EEFF;">systemctl</span><span style="color:#BFF3C2;"> stop</span><span style="color:#BFF3C2;"> evnode</span><span style="color:#BFF3C2;"> ev-reth</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Clear ev-reth data</span></span>\n<span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#FFECB6;"> -rf</span><span style="color:#BFF3C2;"> ~/.ev-reth/db</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Clear ev-node cache</span></span>\n<span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#FFECB6;"> -rf</span><span style="color:#BFF3C2;"> ~/.evnode/data/cache</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Restart</span></span>\n<span class="line"><span style="color:#94EEFF;">systemctl</span><span style="color:#BFF3C2;"> start</span><span style="color:#BFF3C2;"> ev-reth</span><span style="color:#BFF3C2;"> evnode</span></span></code></pre></div><h2 id="performance-issues" tabindex="-1">Performance Issues <a class="header-anchor" href="#performance-issues" aria-label="Permalink to &quot;Performance Issues&quot;">​</a></h2><h3 id="high-memory-usage" tabindex="-1">High Memory Usage <a class="header-anchor" href="#high-memory-usage" aria-label="Permalink to &quot;High Memory Usage&quot;">​</a></h3><ol><li>Reduce cache size in configuration</li><li>Enable lazy aggregation mode</li><li>Limit max pending blocks:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.node.max_pending_blocks</span><span style="color:#FFECB6;"> 50</span></span></code></pre></div><h3 id="high-cpu-usage" tabindex="-1">High CPU Usage <a class="header-anchor" href="#high-cpu-usage" aria-label="Permalink to &quot;High CPU Usage&quot;">​</a></h3><ol><li>Increase block time:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.node.block_time</span><span style="color:#BFF3C2;"> 2s</span></span></code></pre></div><ol><li>Check for transaction spam</li><li>Monitor execution layer performance</li></ol><h3 id="disk-space" tabindex="-1">Disk Space <a class="header-anchor" href="#disk-space" aria-label="Permalink to &quot;Disk Space&quot;">​</a></h3><ol><li>Check disk usage:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">du</span><span style="color:#FFECB6;"> -sh</span><span style="color:#BFF3C2;"> ~/.evnode/data/</span><span style="color:#FFECB6;">*</span></span></code></pre></div><ol><li>Prune old data (if supported by execution layer)</li><li>Consider moving data to larger disk</li></ol><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><ol><li>Check logs for specific error messages</li><li>Search <a href="https://github.com/evstack/ev-node/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li>Join the community Discord for support</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guides/reset-state">Reset State Guide</a> - Detailed reset procedures</li><li><a href="/guides/restart-chain">Restart Chain Guide</a> - Restarting after issues</li><li><a href="/guides/operations/monitoring">Monitoring Guide</a> - Proactive monitoring</li></ul>',86)])])}]]);export{o as __pageData,l as default};
